const express = require('express');
const app = express();

app.get('/api/data', (req, res) => {
  res.json({ items: [] });
});

app.post('/api/data', (req, res) => {
  const { name, value } = req.body;
  res.json({ created: { name, value } });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

