import hashlib

def authenticate(username, password):
    user = get_user(username)
    if not user:
        return False
    hashed = hashlib.sha256(password.encode()).hexdigest()
    if hashed == user['password_hash']:
        return True
    return False

def get_user(username):
    users = {
        'admin': {'password_hash': 'ef92b778bafe771e89245b89ecbc08a44a4e166c06659911881f383d4473e94f'},
    }
    return users.get(username)

The bug: there's no validation that `password` is non-empty. An empty string still gets hashed and compared, and if a user's stored hash happens to match the SHA-256 of an empty string, they get in. More importantly, the function should reject empty credentials upfront.

