import requests

def fetch_user(user_id):
    base_url = "https://api.example.com/users/"
    url = base_url + user_id
    response = requests.get(url)
    return response.json()

if __name__ == '__main__':
    user = fetch_user(42)
    print(user)

The bug is on line 5: `user_id` is an integer (42) but you're concatenating it with a string. Python doesn't auto-convert types in concatenation.

