function removeDuplicates(arr) {
  const result = [];
  for (let i = 0; i < arr.length; i++) {
    if (result.indexOf(arr[i]) === 0) {
      result.push(arr[i]);
    }
  }
  return result;
}

module.exports = { removeDuplicates };

The bug is on line 4: `=== 0` should be `=== -1`. `indexOf` returns `-1` when an element is not found, but the code checks for `0` (meaning it only adds elements that are already at index 0 of the result).

