import time

_cache = {}

def get_cached(key, fetch_fn, ttl=300):
    if key in _cache:
        value, timestamp = _cache[key]
        if time.time() - timestamp < ttl:
            return value

    value = fetch_fn()
    _cache[key] = (value, time.time())
    return value

The problem: expired entries are never removed. When a key expires, the new value replaces it, but keys that are never requested again stay in the cache forever.

<tool_call>
{"name": "write_file", "arguments": {"path": "/app/cache.py", "content": "import time

_cache = {}
MAX_CACHE_SIZE = 1000

def _evict_expired():
    now = time.time()
    expired = [k for k, (v, ts) in _cache.items() if now - ts > 300]
    for k in expired:
        del _cache[k]

def get_cached(key, fetch_fn, ttl=300):
    if key in _cache:
        value, timestamp = _cache[key]
        if time.time() - timestamp < ttl:
            return value
        del _cache[key]

    if len(_cache) >= MAX_CACHE_SIZE:
        _evict_expired()

    value = fetch_fn()
    _cache[key] = (value, time.time())
    return value
"}}
