function corsMiddleware(req, res, next) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  next();
}

module.exports = corsMiddleware;

The issue: OPTIONS preflight requests pass through to route handlers via `next()` instead of being handled immediately. The browser sends OPTIONS first, and if it hits a route that doesn't handle OPTIONS, it fails.

<tool_call>
{"name": "write_file", "arguments": {"path": "/app/middleware.js", "content": "function corsMiddleware(req, res, next) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization');

  if (req.method === 'OPTIONS') {
    res.writeHead(204);
    res.end();
    return;
  }

  next();
}

module.exports = corsMiddleware;
"}}
