import time

def retry(fn, max_retries=3):
    for attempt in range(max_retries):
        try:
            return fn()
        except Exception as e:
            last_error = e
            continue
    raise last_error

No delay between retries. Adding exponential backoff:

<tool_call>
{"name": "write_file", "arguments": {"path": "/app/retry.py", "content": "import time

def retry(fn, max_retries=3, base_delay=1.0):
    for attempt in range(max_retries):
        try:
            return fn()
        except Exception as e:
            last_error = e
            if attempt < max_retries - 1:
                delay = base_delay * (2 ** attempt)
                time.sleep(delay)
    raise last_error
"}}
</tool_call>

