const jwt = require('jsonwebtoken');

function authMiddleware(req, res, next) {
  const token = req.headers.authorization;

  if (!token) {
    return next();
  }

  try {
    const decoded = jwt.decode(token);
    req.user = decoded;
    next();
  } catch (err) {
    next();
  }
}

module.exports = authMiddleware;

Three bugs:
1. Missing token → calls `next()` instead of rejecting (lets unauthenticated requests through)
2. Uses `jwt.decode()` instead of `jwt.verify()` — decode doesn't check the signature, so any forged token works
3. Error handler calls `next()` instead of returning 401

<tool_call>
{"name": "write_file", "arguments": {"path": "/app/src/middleware/auth.js", "content": "const jwt = require('jsonwebtoken');

const JWT_SECRET = process.env.JWT_SECRET;

function authMiddleware(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'No token provided' });
  }

  const token = authHeader.split(' ')[1];

  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Invalid token' });
  }
}

module.exports = authMiddleware;
"}}
